### cors Package

Cross-Origin Resource Sharing (CORS) is a security mechanism that restricts resources from being requested from a different origin.

```bash
npm install cors
```

### Basic Usage

Enable all CORS requests:

```javascript
const cors = require('cors');
app.use(cors());
```

### Configuring Origins

Restrict to specific origins:

```javascript
app.use(cors({
  origin: 'https://myapp.com'
}));

// Multiple origins
app.use(cors({
  origin: ['https://app1.com', 'https://app2.com']
}));

// Dynamic origin
app.use(cors({
  origin: (origin, callback) => {
    if (whitelist.includes(origin) || !origin) {
      callback(null, true);
    } else {
      callback(new Error('Not allowed by CORS'));
    }
  }
}));
```

### Credentials

Allow cookies and auth headers:

```javascript
app.use(cors({
  origin: 'https://myapp.com',
  credentials: true
}));
```

### Allowed Methods and Headers

```javascript
app.use(cors({
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  exposedHeaders: ['X-Total-Count']
}));
```

### Preflight Requests

Browsers send an OPTIONS preflight request before actual cross-origin requests. The cors package handles this automatically.

codeExample:
const cors = require('cors');

const corsOptions = {
  origin: process.env.FRONTEND_URL || 'http://localhost:3000',
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
  allowedHeaders: ['Content-Type', 'Authorization']
};

app.use(cors(corsOptions));

app.options('*', cors(corsOptions)); // Enable preflight for all routes
